"<script setup>\nimport { computed } from 'vue'\nimport alasql from 'alasql'\nimport { useDataStore } from '@/stores/dataStore'\nimport { use, registerTheme } from 'echarts/core'\nimport { CanvasRenderer } from 'echarts/renderers'\nimport { BarChart, LineChart, PieChart, ScatterChart } from 'echarts/charts'\nimport {\n  TitleComponent,\n  TooltipComponent,\n  LegendComponent,\n  GridComponent,\n  DatasetComponent\n} from 'echarts/components'\nimport VChart from 'vue-echarts'\nimport { businessTheme } from './themes/businessTheme'\n\n// Register ECharts core and components\nuse([\n  CanvasRenderer,\n  BarChart,\n  LineChart,\n  PieChart,\n  ScatterChart,\n  TitleComponent,\n  TooltipComponent,\n  LegendComponent,\n  GridComponent,\n  DatasetComponent\n])\n\n// Register custom theme\nregisterTheme('business', businessTheme)\n\nconst props = defineProps({\n  config: {\n    type: Object,\n    required: true,\n    // Expected: { title: '', type: 'bar', dataset: 'dataset1', xAxis: 'col1', yAxis: 'col2', aggregation: 'SUM', orientation: 'vertical' }\n  }\n})\n\nconst dataStore = useDataStore()\n\nconst chartData = computed(() => {\n  if (!props.config.dataset || !props.config.xAxis || !props.config.yAxis) return []\n  \n  const dsName = props.config.dataset\n  const x = props.config.xAxis\n  const y = props.config.yAxis\n  const agg = props.config.aggregation || 'SUM'\n  \n  // Need to execute AlaSQL to group the data\n  try {\n    // Escape column names in case they have spaces\n    const xSafe = `[${x}]`\n    const ySafe = `[${y}]`\n    \n    // For scatter, we don't aggregate, just take raw data\n    if (props.config.type === 'scatter') {\n      const q = `SELECT TOP 500 ${xSafe} as name, ${ySafe} as value FROM [${dsName}] WHERE ${xSafe} IS NOT NULL AND ${ySafe} IS NOT NULL`\n      return alasql(q)\n    }\n    \n    // Grouping query\n    const q = `SELECT ${xSafe} as name, ${agg}(${ySafe}) as value FROM [${dsName}] WHERE ${xSafe} IS NOT NULL GROUP BY ${xSafe} ORDER BY value DESC LIMIT 100`\n    return alasql(q)\n  }
